// Helper: get holidays for a given month
export function getHolidaysForMonth(month: number): Holiday[] {
  return holidays.filter(h => h.month === month);
}

// Helper: get all holidays for a tradition
export function getHolidaysForTradition(traditionKey: string): Holiday[] {
  return holidays.filter(h => h.traditionKey === traditionKey);
}

// Helper: get holiday by slug
export function getHolidayBySlug(slug: string): Holiday | undefined {
  return holidays.find(h => h.slug === slug);
}

